                )
                "SUSPICIOUS" -> listOf(
                    context.getString(R.string.action_caution),
                    context.getString(R.string.action_verify_org)
                )
                else -> emptyList()
            },
            educationalExplanation = cleanExplanation,
            verdictLabel = parsed.verdictLabel
        )
    }"

